// // This module implements a 16-bit up counter with an active-low reset signal. The counter increments on each positive edge of the clock signal. The counter resets to 0 when the reset signal (rst) is inactive.
module down_counter_16bit
(
  input rst,
  input clk,

  output reg [15:0] count
);

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      count <= 16'b0000000000000000;
    end 
	else 
	begin
      count <= count - 1;
    end
  end

endmodule
